#:property AllowUnsafeBlocks=true

Console.WriteLine($"nint size: {nint.Size} bytes");

// stackalloc Span<nint>
Span<nint> signedSpan = stackalloc nint[5];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = i * 10;

Console.WriteLine("Span<nint> via stackalloc:");
foreach (var val in signedSpan)
    Console.WriteLine($"  {val}");

// stackalloc Span<nuint>
Span<nuint> unsignedSpan = stackalloc nuint[5];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 100);

Console.WriteLine("Span<nuint> via stackalloc:");
foreach (var val in unsignedSpan)
    Console.WriteLine($"  {val}");

Console.WriteLine("\nSuccess! stackalloc with nint/nuint works.");

